  /* Colors - Neutral */
  --clr-navy-950: hsl(226, 43%, 10%);
  --clr-navy-900: hsl(235, 46%, 20%);
  --clr-purple-500: hsl(235, 45%, 61%);
  --clr-navy-200: hsl(236, 100%, 87%);

  /* Typography */
  --ff-rubik: 'Rubik', sans-serif;
  --fw-light: 300;
  --fw-regular: 400;
  --fw-medium: 500;

  /* Spacing */
  --card-radius: 1rem;
  --grid-gap: 1.5rem;
}

/* ===== Reset & Base ===== */
*,
*::before,
*::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: var(--ff-rubik);
  font-weight: var(--fw-regular);
  background-color: var(--clr-navy-950);
  color: white;
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 1.5rem;
}

/* ===== Dashboard Grid ===== */
.dashboard {
  display: grid;
  grid-template-columns: 1fr;
  gap: var(--grid-gap);
  max-width: 69rem;
  width: 100%;
}

.activity-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: var(--grid-gap);
}

/* ===== Profile Card ===== */
.card--profile {
  background-color: var(--clr-navy-900);
  border-radius: var(--card-radius);
  overflow: hidden;
}

.profile__header {
  background-color: var(--clr-purple-600);
  padding: 2rem;
  border-radius: var(--card-radius);
  display: flex;
  align-items: center;
  gap: 1.25rem;
}

.profile__avatar {
  width: 4.5rem;
  height: 4.5rem;
  border-radius: 50%;
  border: 3px solid white;
  object-fit: cover;
}

.profile__info {
  display: flex;
  flex-direction: column;
}

.profile__label {
  font-size: 0.85rem;
  font-weight: var(--fw-regular);
  color: var(--clr-navy-200);
  opacity: 0.8;
}

.profile__name {
  font-size: 1.4rem;
  font-weight: var(--fw-light);
  line-height: 1.2;
  margin-top: 0.25rem;
}

.profile__timeframes {
  padding: 1.25rem 2rem;
  display: flex;
  justify-content: space-between;
}

.timeframe-btn {
  background: none;
  border: none;
  font-family: var(--ff-rubik);
  font-size: 1rem;
  font-weight: var(--fw-regular);
  color: var(--clr-purple-500);
  cursor: pointer;
  padding: 0.25rem 0;
  transition: color 0.2s ease;
}

.timeframe-btn:hover,
.timeframe-btn:focus-visible {
  color: var(--clr-navy-200);
}

.timeframe-btn.active {
  color: white;
