// Loads the page in a headless environment, inspects DOM, simulates interactions,
// and generates a JSON report of test results.

const fs = require('fs');
const path = require('path');

// Simple test framework
const results = [];
let totalTests = 0;

function describe(name, fn) {
  console.log(`\n📦 ${name}`);
  fn();
}

function test(name, fn) {
  totalTests++;
  try {
    fn();
    results.push({ name, status: 'passed' });
    console.log(`  ✅ ${name}`);
  } catch (err) {
    results.push({ name, status: 'failed', error: err.message });
    console.log(`  ❌ ${name}: ${err.message}`);
  }
}

function assert(condition, message) {
  if (!condition) throw new Error(message || 'Assertion failed');
}

function assertEqual(actual, expected, message) {
  if (actual !== expected) {
    throw new Error(
      message || `Expected "${expected}" but got "${actual}"`
    );
  }
}

function assertIncludes(str, substr, message) {
  if (!str.includes(substr)) {
    throw new Error(
      message || `Expected "${str}" to include "${substr}"`
    );
  }
}

// ===== Read and parse source files =====
const htmlPath = path.join(__dirname, 'index.html');
const cssPath = path.join(__dirname, 'styles.css');
const jsPath = path.join(__dirname, 'script.js');
const dataPath = path.join(__dirname, 'data.json');

const htmlContent = fs.readFileSync(htmlPath, 'utf-8');
const cssContent = fs.readFileSync(cssPath, 'utf-8');
const jsContent = fs.readFileSync(jsPath, 'utf-8');
let dataContent;
try {
  dataContent = JSON.parse(fs.readFileSync(dataPath, 'utf-8'));
} catch (e) {
  dataContent = null;
}

// ===== HTML Structure Tests =====
describe('HTML Structure', () => {
  test('index.html exists and is non-empty', () => {
    assert(htmlContent.length > 0, 'HTML file is empty');
  });

  test('HTML has proper doctype', () => {
    assert(htmlContent.toLowerCase().includes('<!doctype html'), 'Missing doctype');
  });

  test('HTML has viewport meta tag', () => {
    assertIncludes(htmlContent, 'viewport', 'Missing viewport meta tag');
  });

  test('HTML links styles.css', () => {
    assertIncludes(htmlContent, 'styles.css', 'Missing styles.css link');
  });

  test('HTML includes script.js', () => {
    assertIncludes(htmlContent, 'script.js', 'Missing script.js reference');
  });

  test('Profile card section exists', () => {
    assert(
      htmlContent.includes('card--profile') ||
        htmlContent.includes('profile') ||
        htmlContent.includes('jeremy'),
      'Missing profile/user card section'
    );
  });

  test('Timeframe buttons exist (Daily, Weekly, Monthly)', () => {
    const hasDaily = htmlContent.toLowerCase().includes('daily');
    const hasWeekly = htmlContent.toLowerCase().includes('weekly');
    const hasMonthly = htmlContent.toLowerCase().includes('monthly');
    assert(hasDaily, 'Missing Daily timeframe button');
    assert(hasWeekly, 'Missing Weekly timeframe button');
    assert(hasMonthly, 'Missing Monthly timeframe button');
  });

  test('Activity cards container exists for JS rendering', () => {
    assert(
      htmlContent.includes('activity-cards') ||
        htmlContent.includes('activity-grid') ||
        htmlContent.includes('card--activity'),
      'Missing activity cards container or class'
    );
  });

  test('Jeremy Robson name present', () => {
    assertIncludes(htmlContent, 'Jeremy', 'Missing Jeremy name');
    assertIncludes(htmlContent, 'Robson', 'Missing Robson name');
  });

  test('Profile avatar image reference exists', () => {
    assert(
      htmlContent.includes('image-jeremy') ||
        htmlContent.includes('jeremy.png'),
      'Missing Jeremy avatar image'
    );
  });

  test('Uses semantic HTML elements', () => {
    const hasSemantic =
      htmlContent.includes('<main') ||
      htmlContent.includes('<section') ||
      htmlContent.includes('<nav') ||
      htmlContent.includes('<article');
    assert(hasSemantic, 'No semantic HTML elements found');
  });

  test('ARIA attributes present for accessibility', () => {
    const hasAria =
      htmlContent.includes('aria-label') ||
      htmlContent.includes('aria-pressed') ||
      htmlContent.includes('aria-live');
    assert(hasAria, 'No ARIA attributes found');
  });
});

// ===== CSS Tests =====
describe('CSS Styles', () => {
  test('styles.css exists and is non-empty', () => {
    assert(cssContent.length > 0, 'CSS file is empty');
  });

  test('CSS uses custom properties (variables)', () => {
    assert(cssContent.includes('--'), 'No CSS custom properties found');
  });

  test('CSS uses CSS Grid', () => {
    assert(
      cssContent.includes('grid') || cssContent.includes('Grid'),
      'No CSS Grid usage found'
    );
  });

  test('CSS has responsive media queries', () => {
    assert(
      cssContent.includes('@media'),
      'No media queries found for responsive design'
    );
  });

  test('CSS includes Rubik font family', () => {
    assert(
      cssContent.toLowerCase().includes('rubik'),
      'Missing Rubik font family'
    );
  });

  test('CSS defines activity card colors', () => {
    const hasWork =
      cssContent.includes('work') && cssContent.includes('orange');
    const colorVars =
      cssContent.includes('15, 100%, 70%') ||
      cssContent.includes('195, 74%, 62%') ||
      cssContent.includes('348, 100%, 68%') ||
      cssContent.includes('--clr-orange');
    assert(colorVars, 'Missing activity card color definitions');
  });

  test('CSS has hover states', () => {
    assert(cssContent.includes(':hover'), 'No hover states defined');
  });

  test('CSS has focus-visible states', () => {
    assert(
      cssContent.includes(':focus-visible') || cssContent.includes(':focus'),
      'No focus states defined'
    );
  });

  test('CSS uses the navy background color', () => {
    assert(
      cssContent.includes('226, 43%, 10%') ||
        cssContent.includes('--clr-navy-950'),
      'Missing navy 950 background color'
    );
  });

  test('CSS uses the dark card background', () => {
    assert(
      cssContent.includes('235, 46%, 20%') ||
        cssContent.includes('--clr-navy-900'),
      'Missing navy 900 card background color'
    );
  });

  test('CSS has transition animations', () => {
    assert(cssContent.includes('transition'), 'No transitions defined');
  });
});

// ===== JavaScript Tests =====
describe('JavaScript Logic', () => {
  test('script.js exists and is non-empty', () => {
    assert(jsContent.length > 0, 'JS file is empty');
  });

  test('JS fetches data.json', () => {
    assert(
      jsContent.includes('data.json') ||
        jsContent.includes('fetch') ||
        jsContent.includes('getJSON'),
      'JS does not load data from data.json'
    );
  });

  test('JS handles timeframe switching', () => {
    const hasDaily = jsContent.includes('daily');
    const hasWeekly = jsContent.includes('weekly');
    const hasMonthly = jsContent.includes('monthly');
    assert(hasDaily && hasWeekly && hasMonthly, 'JS does not handle all timeframes');
  });

  test('JS implements previous period labels', () => {
    const hasYesterday = jsContent.includes('Yesterday');
    const hasLastWeek = jsContent.includes('Last Week');
    const hasLastMonth = jsContent.includes('Last Month');
    assert(
      hasYesterday && hasLastWeek && hasLastMonth,
      'Missing previous period labels (Yesterday, Last Week, Last Month)'
    );
  });

  test('JS handles click events on timeframe buttons', () => {
    assert(
      jsContent.includes('click') || jsContent.includes('addEventListener'),
      'No click event handling found'
    );
  });

  test('JS renders activity cards dynamically', () => {
    const createsElements =
      jsContent.includes('createElement') ||
      jsContent.includes('innerHTML') ||
      jsContent.includes('insertAdjacentHTML');
    assert(createsElements, 'No dynamic card rendering found');
  });

  test('JS handles hour formatting (hr vs hrs)', () => {
    assert(
      jsContent.includes('hr') && (jsContent.includes('hrs') || jsContent.includes('1hr')),
      'No hour formatting logic found'
    );
  });

  test('JS includes all activity types', () => {
    const activities = ['Work', 'Play', 'Study', 'Exercise', 'Social', 'Self Care'];
    activities.forEach((act) => {
      assert(
        jsContent.includes(act),
        `Missing activity type: ${act}`
      );
    });
  });
});

// ===== Data Tests =====
describe('Data Integrity', () => {
  test('data.json exists and is valid JSON', () => {
    assert(dataContent !== null, 'data.json is missing or invalid');
  });

  test('data.json has 6 activities', () => {
    assert(dataContent && dataContent.length === 6, `Expected 6 activities, got ${dataContent ? dataContent.length : 0}`);
  });

  test('Each activity has title and all timeframes', () => {
    const requiredTimeframes = ['daily', 'weekly', 'monthly'];
    dataContent.forEach((item) => {
      assert(item.title, 'Activity missing title');
      assert(item.timeframes, `Activity "${item.title}" missing timeframes`);
      requiredTimeframes.forEach((tf) => {
        assert(
          item.timeframes[tf],
          `Activity "${item.title}" missing ${tf} timeframe`
        );
        assert(
          typeof item.timeframes[tf].current === 'number',
          `Activity "${item.title}" ${tf} current is not a number`
        );
        assert(
          typeof item.timeframes[tf].previous === 'number',
          `Activity "${item.title}" ${tf} previous is not a number`
        );
      });
    });
  });

