// Renders activity cards from data.json and handles timeframe switching

(function () {
  'use strict';

  // Mapping of activity titles to CSS class names and icon files
  const ACTIVITY_CONFIG = {
    Work: { className: 'work', icon: 'icon-work.svg' },
    Play: { className: 'play', icon: 'icon-play.svg' },
    Study: { className: 'study', icon: 'icon-study.svg' },
    Exercise: { className: 'exercise', icon: 'icon-exercise.svg' },
    Social: { className: 'social', icon: 'icon-social.svg' },
    'Self Care': { className: 'self-care', icon: 'icon-self-care.svg' },
  };

  // Labels for previous timeframe
  const PREVIOUS_LABELS = {
    daily: 'Yesterday',
    weekly: 'Last Week',
    monthly: 'Last Month',
  };

  let currentTimeframe = 'weekly';
  let activityData = [];

  // Fetch data from data.json
  async function fetchData() {
    try {
      const response = await fetch('data.json');
      if (!response.ok) throw new Error('Failed to load data.json');
      return await response.json();
    } catch (err) {
      console.error('Error loading data:', err);
      return [];
    }
  }

  // Format hours display
  function formatHours(hours) {
    return hours === 1 ? `${hours}hr` : `${hours}hrs`;
  }

  // Create a single activity card DOM element
  function createActivityCard(activity, timeframe) {
    const config = ACTIVITY_CONFIG[activity.title] || {
      className: activity.title.toLowerCase().replace(/\s+/g, '-'),
      icon: '',
    };

    const tf = activity.timeframes[timeframe];
    const previousLabel = PREVIOUS_LABELS[timeframe];

    const card = document.createElement('article');
    card.className = `card card--activity card--${config.className}`;
    card.setAttribute('data-activity', activity.title);
    card.setAttribute('aria-label', `${activity.title} time tracking`);

    card.innerHTML = `
      <div class="activity__header">
        <img src="./images/${config.icon}" alt="" class="activity__icon" aria-hidden="true">
      </div>
      <div class="activity__content">
        <div class="activity__title-row">
          <h2 class="activity__title">${activity.title}</h2>
          <button class="activity__menu" aria-label="More options for ${activity.title}">
            <svg width="21" height="5" viewBox="0 0 21 5" xmlns="http://www.w3.org/2000/svg">
              <circle cx="2.5" cy="2.5" r="2.5" fill="currentColor"/>
              <circle cx="10.5" cy="2.5" r="2.5" fill="currentColor"/>
              <circle cx="18.5" cy="2.5" r="2.5" fill="currentColor"/>
            </svg>
          </button>
        </div>
        <div class="activity__hours-row">
          <span class="activity__hours" data-current>${formatHours(tf.current)}</span>
          <span class="activity__previous" data-previous>${previousLabel} - ${formatHours(tf.previous)}</span>
        </div>
      </div>
    `;

    return card;
  }

  // Render all activity cards
  function renderCards(data, timeframe) {
    const container = document.getElementById('activity-cards');
    container.innerHTML = '';
    data.forEach((activity) => {
      const card = createActivityCard(activity, timeframe);
      container.appendChild(card);
    });
  }

  // Update existing cards when switching timeframes (no full re-render)
  function updateCards(data, timeframe) {
    const previousLabel = PREVIOUS_LABELS[timeframe];
    data.forEach((activity) => {
      const card = document.querySelector(`[data-activity="${activity.title}"]`);
      if (!card) return;
      const tf = activity.timeframes[timeframe];
      const currentEl = card.querySelector('[data-current]');
      const previousEl = card.querySelector('[data-previous]');
      if (currentEl) currentEl.textContent = formatHours(tf.current);
      if (previousEl) previousEl.textContent = `${previousLabel} - ${formatHours(tf.previous)}`;
    });
  }

  // Handle timeframe button clicks
  function handleTimeframeClick(e) {
    const btn = e.target.closest('.timeframe-btn');
    if (!btn) return;

    const timeframe = btn.dataset.timeframe;
    if (timeframe === currentTimeframe) return;

    // Update active state
    document.querySelectorAll('.timeframe-btn').forEach((b) => {
      b.classList.remove('active');
      b.setAttribute('aria-pressed', 'false');
    });
    btn.classList.add('active');
    btn.setAttribute('aria-pressed', 'true');

    currentTimeframe = timeframe;
    updateCards(activityData, timeframe);
  }

  // Initialize
  async function init() {
    activityData = await fetchData();
    renderCards(activityData, currentTimeframe);

    // Attach event listener to timeframe buttons
    const timeframesNav = document.querySelector('.profile__timeframes');
    if (timeframesNav) {
      timeframesNav.addEventListener('click', handleTimeframeClick);
    }
  }

  // Start when DOM is ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
